import type { ButtonTone, ButtonVariant } from "@/components/control-ui/contracts";
import { SendAurora } from "@/components/control-ui/extensions/send-aurora";
import type { ControlUiSkin } from "@/components/control-ui/skin";

const focus = "focus-visible:ring-2 focus-visible:ring-[var(--ring)] focus-visible:ring-offset-2 focus-visible:ring-offset-background";
// press feel every cuicui control shares; rides skinSlot eviction since recipes paint transition/scale/shadow as utilities (skin.css [data-control] rule would silently lose)
// shadow-(--x) not shadow-[var(--x)]: tailwind-merge classes the var() arbitrary form as a shadow COLOR, would keep recipe's box-shadow beside it
const controlMotion =
  "transition-[background-color,border-color,box-shadow,transform] duration-[var(--duration-fast)] ease-[var(--ease-standard)] active:scale-[0.96]";
const control = `rounded-[var(--radius-control)] border border-[var(--cuicui-border)] bg-[var(--cuicui-control-bg)] text-foreground shadow-(--cuicui-control-shadow) ${controlMotion} hover:bg-[var(--cuicui-control-hover)] ${focus}`;
const solid = `cuicui-gradient-fill rounded-[var(--radius-control)] border border-transparent text-white shadow-(--cuicui-solid-shadow) ${controlMotion} ${focus}`;
const danger = `rounded-[var(--radius-control)] border border-transparent bg-[var(--destructive)] text-[var(--destructive-foreground)] shadow-(--cuicui-control-shadow) ${controlMotion} hover:brightness-105 ${focus}`;
const field = `rounded-[var(--radius-control)] border border-[var(--input)] bg-[var(--cuicui-field-bg)] text-foreground shadow-(--cuicui-control-shadow) ${focus}`;
const popup =
  "rounded-[var(--radius-popover)] border border-[var(--cuicui-border)] bg-popover/90 p-1 shadow-(--shadow-pop) backdrop-blur-[var(--backdrop-blur-popover)]";
const item =
  "rounded-[var(--radius-popup-item)] px-2.5 py-1 text-[13px] data-[highlighted]:bg-[var(--cuicui-control-bg)] data-[disabled]:opacity-45";
const label = "px-2 py-1 text-[11px] font-medium uppercase tracking-[0.08em] text-muted-foreground";
const separator = "mx-1 my-1 bg-[var(--cuicui-border)]";
const surface =
  "rounded-[var(--radius-panel)] border border-[var(--cuicui-border)] bg-[var(--cuicui-surface-bg)] shadow-(--shadow-soft) backdrop-blur-[var(--backdrop-blur-popover)]";
const flatSurface = "rounded-[var(--radius-panel)] border border-[var(--cuicui-border)] bg-[var(--cuicui-surface-bg)]";
const shellItem =
  "rounded-[var(--radius)] border border-transparent px-3 font-medium text-sm text-black/40 hover:bg-black/5 hover:text-black/70 dark:text-white/40 dark:hover:bg-white/10 dark:hover:text-white/70 data-[active=true]:bg-black/5 data-[active=true]:text-black/70 dark:data-[active=true]:bg-white/10 dark:data-[active=true]:text-white/80";

function button(variant: ButtonVariant, tone: ButtonTone) {
  if (tone === "danger") return danger;
  if (variant === "solid") return solid;
  return control;
}

export const skin: ControlUiSkin = {
  id: "cuicui",
  sidebarLayout: "sidebar",
  sidebarWidth: "20rem",
  adornments: {
    "chat-input": {
      "send-layer": (ctx) => (
        <SendAurora
          sendCount={ctx.sendCount}
          colors={["var(--cuicui-pink)", "var(--cuicui-orange)", "var(--cuicui-yellow)", "var(--cuicui-sky)", "var(--cuicui-blue)"]}
        />
      ),
    },
  },
  slots: {
    button: {
      root: ({ variant, tone }) => button(variant, tone),
      content: "gap-1.5",
    },
    select: {
      content: popup,
      trigger: control,
      item: item,
    },
    menu: {
      trigger: control,
      content: popup,
      item: item,
      separator: separator,
      label: label,
    },
    "context-menu": {
      content: popup,
      "sub-content": popup,
      item: item,
      "checkbox-item": item,
      "radio-item": item,
      "sub-trigger": `${item} data-[popup-open]:bg-[var(--cuicui-control-bg)]`,
      separator: separator,
      label: label,
      shortcut: "ml-auto text-[11px] tracking-wide text-muted-foreground",
    },
    menubar: {
      trigger: control,
      content: popup,
      "sub-content": popup,
      item: item,
      separator: separator,
      label: label,
    },
    input: {
      root: field,
    },
    "input-group": {
      root: field,
    },
    "native-select": {
      root: field,
    },
    textarea: {
      root: field,
    },
    combobox: {
      input: field,
      content: popup,
    },
    autocomplete: {
      input: field,
      content: popup,
    },
    "number-field": {
      group: field,
    },
    "color-picker": {
      content: `${popup} p-3`,
      panel: `${popup} p-3`,
    },
    "navigation-menu": {
      viewport: popup,
    },
    command: {
      root: `${popup} overflow-hidden`,
      "input-wrapper": "border-b border-[var(--cuicui-border)]",
      item: `${item} data-[selected=true]:bg-[var(--cuicui-control-bg)]`,
    },
    "trigger-menu": {
      root: popup,
      item: item,
      "group-label": label,
    },
    dialog: {
      content: `${surface} p-6`,
      title: "text-[15px] font-semibold tracking-[-0.01em]",
      description: "text-body text-muted-foreground",
    },
    "alert-dialog": {
      content: `${surface} p-6`,
    },
    sheet: {
      content: surface,
    },
    toast: {
      root: flatSurface,
    },
    popover: {
      content: popup,
    },
    "hover-card": {
      content: popup,
    },
    tooltip: {
      content:
        "rounded-[var(--radius-control)] border border-[var(--cuicui-border)] bg-popover px-2.5 py-1.5 text-[12px] shadow-(--shadow-pop)",
    },
    sidebar: {
      wrapper:
        "relative isolate bg-[var(--cuicui-page-from)] bg-[image:var(--cuicui-page-bg)] has-data-[variant=inset]:bg-[var(--cuicui-page-from)]",
      inset: "bg-[var(--cuicui-page-from)] bg-[image:var(--cuicui-page-bg)]",
      inner: "bg-transparent border-0 rounded-none p-3 shadow-none backdrop-blur-none text-sidebar-foreground",
      "menu-button": shellItem,
      "group-label": "px-3 py-1 text-xs font-medium tracking-tight text-neutral-500 dark:text-neutral-400",
    },
    "sidebar-layout": {
      content:
        "rounded-[var(--radius)] border border-[var(--cuicui-container-border)] bg-[var(--cuicui-main-container)] shadow-none backdrop-blur-none lg:mr-6 lg:mb-6",
    },
    tabs: {
      list: "rounded-[var(--radius-control)] bg-[var(--cuicui-control-bg)] p-1",
      tab: "rounded-[calc(var(--radius-control)*0.78)] font-medium data-[active]:text-white",
      indicator: "rounded-[calc(var(--radius-control)*0.78)]",
    },
    card: {
      root: surface,
    },
    alert: {
      root: flatSurface,
    },
    badge: {
      root: "rounded-full border border-[var(--cuicui-border)] bg-[var(--cuicui-control-bg)] px-2.5 py-0.5 font-medium text-muted-foreground",
    },
    item: {
      root: "rounded-[var(--radius-control)] border border-transparent hover:border-[var(--cuicui-border)] hover:bg-[var(--cuicui-control-bg)]",
    },
    empty: {
      root: "rounded-[var(--radius-panel)] border border-dashed border-[var(--cuicui-border)] bg-[var(--cuicui-surface-bg)]",
      media: "rounded-[var(--radius-control)] bg-[var(--cuicui-gradient-soft)]",
    },
    slider: {
      track: "rounded-full bg-[var(--cuicui-control-bg)]",
      indicator: "rounded-full bg-[var(--primary)]",
      thumb: `${control} shadow-(--shadow-sm)`,
    },
    switch: {
      root: "bg-[var(--cuicui-control-bg)] data-[checked]:bg-[var(--primary)]",
    },
    checkbox: {
      root: "rounded-[calc(var(--radius-control)*0.55)] border-[var(--cuicui-border)] data-[checked]:bg-[var(--primary)] data-[checked]:text-primary-foreground",
    },
    "radio-group": {
      item: "border-[var(--cuicui-border)] data-[checked]:border-[var(--primary)]",
    },
    "chat-scene": {
      root: surface,
    },
    activity: {
      root: ({ kind }) => (kind === "tool" ? surface : undefined),
      trigger: ({ kind }) => (kind === "tool" ? "bg-[var(--cuicui-control-bg)]" : undefined),
      status: ({ kind }) => (kind === "tool" ? "cuicui-gradient-text font-medium" : undefined),
    },
    "chat-message": {
      avatar: "rounded-full border border-[var(--cuicui-border)] bg-[var(--cuicui-control-bg)]",
      content: ({ role }) =>
        role === "user"
          ? "cuicui-gradient-fill rounded-[var(--radius-field)] text-white shadow-(--shadow-sm)"
          : "rounded-[var(--radius-field)] bg-transparent",
    },
    "chat-input": {
      shell: `${field} rounded-[var(--radius-field)]`,
      submit: solid,
      mention: "rounded-full border border-[var(--cuicui-border)] bg-[var(--cuicui-control-bg)]",
    },
    "markdown-block": {
      root: surface,
      header: "border-b border-[var(--cuicui-border)] bg-[var(--cuicui-control-bg)]",
      title: "font-semibold tracking-[-0.01em]",
    },
    markdown: {
      root: "text-foreground",
    },
    code: {
      root: surface,
      header: "border-b border-[var(--cuicui-border)] bg-[var(--cuicui-control-bg)]",
      title: "font-mono text-[12px] text-muted-foreground",
    },
    "code-diff": {
      root: surface,
      header: "border-b border-[var(--cuicui-border)] bg-[var(--cuicui-control-bg)]",
    },
    "inline-attachment": {
      root: flatSurface,
      image: "rounded-[var(--radius-control)]",
    },
    "thread-rail": {
      item: "rounded-full bg-[var(--cuicui-control-bg)]",
      popover: popup,
    },
    progress: {
      track: "bg-[var(--cuicui-control-bg)]",
      indicator: "bg-[var(--primary)]",
    },
    meter: {
      track: "bg-[var(--cuicui-control-bg)]",
      indicator: "bg-[var(--primary)]",
    },
  },
  paints: {
    "chat-message": {
      streaming: "cuicui-gradient-text",
    },
    skeleton: {
      shimmer: "cuicui-animated-gradient",
    },
  },
};

[data-skin="cuicui"] {
  --cuicui-sky: oklch(0.7676 0.1305 225.406);
  --cuicui-violet: oklch(0.6131 0.2067 283.833);
  --cuicui-rose: oklch(0.6851 0.1761 14.132);
  --cuicui-orange: oklch(0.7259 0.1609 48.691);
  --cuicui-yellow: oklch(0.8659 0.1539 86.484);
  --cuicui-pink: oklch(0.651 0.2092 346.41);
  --cuicui-blue: oklch(0.6871 0.1707 250.704);
  --cuicui-mint: oklch(0.8983 0.0973 174.414);
  --cuicui-gradient: linear-gradient(135deg, var(--cuicui-sky), var(--cuicui-violet), var(--cuicui-rose), var(--cuicui-orange));
  --cuicui-gradient-text: linear-gradient(to right, var(--cuicui-sky), var(--cuicui-violet), var(--cuicui-rose), var(--cuicui-orange));
  --cuicui-gradient-top: linear-gradient(-45deg, var(--cuicui-yellow), var(--cuicui-pink), var(--cuicui-blue), var(--cuicui-mint));
  --cuicui-gradient-soft: linear-gradient(
    135deg,
    oklch(from var(--cuicui-sky) l c h / 0.16),
    oklch(from var(--cuicui-violet) l c h / 0.18),
    oklch(from var(--cuicui-orange) l c h / 0.16)
  );
  --cuicui-noise: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' version='1.1' xmlnsXlink='http://www.w3.org/1999/xlink' viewBox='0 0 700 700' width='700' height='700' opacity='1'%3e%3ctitle%3enoise%3c/title%3e%3cdefs%3e%3cfilter id='nnnoise-filter' x='-20%25' y='-20%25' width='140%25' height='140%25' filterUnits='objectBoundingBox' primitiveUnits='userSpaceOnUse' color-interpolation-filters='linearRGB'%3e%3cfeTurbulence type='fractalNoise' baseFrequency='0.2' numOctaves='4' seed='15' stitchTiles='stitch' x='0%25' y='0%25' width='100%25' height='100%25' result='turbulence'/%3e%3cfeSpecularLighting surfaceScale='5' specularConstant='0.8' specularExponent='20' lighting-color='white' x='0%25' y='0%25' width='100%25' height='100%25' in='turbulence' result='specularLighting'%3e%3cfeDistantLight azimuth='3' elevation='96'/%3e%3c/feSpecularLighting%3e%3cfeColorMatrix type='saturate' values='0' x='0%25' y='0%25' width='100%25' height='100%25' in='specularLighting' result='colormatrix'/%3e%3c/filter%3e%3c/defs%3e%3crect width='700' height='700' fill='black'/%3e%3crect width='700' height='700' fill='white' filter='url(%23nnnoise-filter)'/%3e%3c/svg%3e");
  --cuicui-page-from: oklch(1 0 0);
  --cuicui-page-to: oklch(0.985 0 0);
  --cuicui-page-bg: linear-gradient(to top, var(--cuicui-page-from), var(--cuicui-page-to));
  --cuicui-main-container: oklch(0.985 0 0);
  --cuicui-container-border: oklch(0.708 0 0 / 0.2);
  --cuicui-surface-bg: oklch(1 0 0 / 0.84);
  --cuicui-surface-hover: oklch(1 0 0 / 0.66);
  --cuicui-control-bg: oklch(0.922 0 0 / 0.42);
  --cuicui-control-hover: oklch(0.922 0 0 / 0.28);
  --cuicui-field-bg: oklch(1 0 0 / 0.9);
  --cuicui-border: oklch(from var(--foreground) l c h / 0.16);
  --cuicui-control-shadow: 0 1px 2px oklch(from var(--shadow-color) l c h / 0.06);
  --cuicui-solid-shadow: inset 0 1px 0 oklch(1 0 0 / 0.28), 0 8px 24px oklch(from var(--primary) l c h / 0.24);
}

:where(.dark) [data-skin="cuicui"],
.dark[data-skin="cuicui"] {
  --cuicui-page-from: oklch(0.145 0 0);
  --cuicui-page-to: oklch(0.269 0 0);
  --cuicui-main-container: oklch(0.173 0 0);
  --cuicui-surface-bg: oklch(0.205 0 0 / 0.82);
  --cuicui-surface-hover: oklch(0.269 0 0 / 0.68);
  --cuicui-control-bg: oklch(0.708 0 0 / 0.14);
  --cuicui-control-hover: oklch(0.708 0 0 / 0.2);
  --cuicui-field-bg: oklch(0.173 0 0 / 0.76);
  --cuicui-border: oklch(1 0 0 / 0.13);
  --cuicui-control-shadow: 0 1px 2px oklch(0 0 0 / 0.18);
}

@layer base {
  :root[data-skin="cuicui"] body {
    min-height: 100dvh;
    background-color: var(--cuicui-page-from);
    background-image: var(--cuicui-page-bg);
  }

  :root[data-skin="cuicui"] body::after {
    content: "";
    position: fixed;
    inset: 0;
    z-index: 9999;
    pointer-events: none;
    user-select: none;
    background-image: var(--cuicui-noise);
    background-size: 400px;
    opacity: 0.05;
    filter: invert(1);
  }

  :root.dark[data-skin="cuicui"] body::after {
    filter: none;
  }
}

/* slot restyles (single slots + families like control chrome, popup surfaces) live in skin.config, NOT here —
 * library recipes paint those as utilities, so a skin.css rule w/o `!important` silently loses
 * this file used to carry a [data-control] press-feel family + popup-surface :is() family, both provably dead for that reason, now ride config's consts; keeps only what classes cannot say */
@layer components {
  [data-skin="cuicui"] .cuicui-gradient-fill {
    background-color: var(--primary);
    background-image: var(--cuicui-gradient);
  }

  [data-skin="cuicui"] .cuicui-gradient-text {
    background-image: var(--cuicui-gradient-text);
    background-clip: text;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    color: transparent;
  }

  [data-skin="cuicui"] .cuicui-animated-gradient {
    background-image: var(--cuicui-gradient-top);
    background-size: 400% 400%;
    animation: cuicui-gradient-animation 5s ease infinite;
  }

  [data-skin="cuicui"] [data-control-ui="tabs"][data-slot="indicator"] {
    background: var(--cuicui-gradient-text);
    box-shadow: 0 0 20px oklch(from var(--primary) l c h / 0.22);
  }

  [data-skin="cuicui"] [data-control-ui="tabs"][data-slot="tab"] {
    letter-spacing: -0.01em;
  }

}

@keyframes cuicui-gradient-animation {
  0% {
    -webkit-background-position: 0% 50%;
    background-position: 0% 50%;
  }

  50% {
    -webkit-background-position: 100% 50%;
    background-position: 100% 50%;
  }

  100% {
    -webkit-background-position: 0% 50%;
    background-position: 0% 50%;
  }
}

@media (prefers-reduced-motion: reduce) {
  [data-skin="cuicui"] .cuicui-animated-gradient {
    animation: none;
  }
}

/* Cuicui owns the complete token contract: neutral surfaces, DM Sans rhythm, rounded copy-paste cards,
 * and a violet-led accent. Texture, gradient, and glass details live in skin.css; shared @theme bindings live in core. */

[data-skin="cuicui"] {
  --font-sans: "DM Sans", ui-sans-serif, system-ui, -apple-system, "Segoe UI", sans-serif;
  --font-mono: "Geist Mono", "SF Mono", ui-monospace, Menlo, Consolas, monospace;

  /* type scale — small chrome bumped one rung (11/12/13px micro/meta/label); body stays 14px */
  --text-micro: 0.6875rem;
  --text-meta: 0.75rem;
  --text-label: 0.8125rem;

  --primary: oklch(0.574 0.2067 283.833);
  --primary-foreground: oklch(1 0 0);
  --primary-text: oklch(from var(--primary) 0.48 c h);
  --destructive: oklch(0.576 0.1761 14.132);
  --destructive-foreground: oklch(1 0 0);
  --destructive-text: oklch(from var(--destructive) 0.48 c h);

  --ring-opacity: 1;
  --popover-opacity: 0.9;
  --backdrop-blur-popover: 16px;
  --overlay-opacity: 0.36;
  --backdrop-blur-overlay: 8px;
  --scroll-fade-size: 2.25rem;

  --shadow-color: oklch(0.145 0 0);
  --shadow-size: 0.7;
  --shadow-opacity: 0.9;
  --shadow-y: 1;
  --shadow-control-multiplier: 0.8;
  --shadow-panel-multiplier: 1.8;
  --shadow-popover-multiplier: 3.2;
  --shadow-modal-multiplier: 4.2;
  --shadow-ambient-multiplier: 6;

  --radius: 10px;
  --radius-control: var(--radius);
  /* radius divergences — copy-paste cards: panels at base radius, 1.85× field, 2× scene; other rungs keep Refined ratios */
  --radius-field: calc(var(--radius) * 1.85);
  --radius-panel: var(--radius);
  --radius-scene: calc(var(--radius) * 2);
  --corner-shape: round;
  --corner-shape-control: var(--corner-shape);
  --corner-shape-popover: var(--corner-shape);
  --corner-shape-panel: var(--corner-shape);

  --popover-padding: 0.375rem;
  --radius-popup-item: calc(var(--radius-control) * 0.72);
  --nest-safe: 1px;
  --nest-corner-ratio: 3.41421356;
  --radius-popup-item-fit: min(var(--radius-popup-item), calc(var(--control-h-xs) / 2));
  --radius-popover: calc(var(--radius-popup-item-fit) + clamp(0px, var(--radius-popup-item-fit) * 1000, var(--popover-padding) - 1px));

  --padding-x: 1rem;
  --padding-y: 0.625rem;

  --control-h: 2rem;
  --control-h-xs: round(var(--control-h) * 0.7, 1px);
  --control-h-sm: round(var(--control-h) * 0.85, 1px);
  --control-h-md: var(--control-h);
  --control-h-lg: round(var(--control-h) * 1.12, 1px);

  --ease-standard: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-emphasized: cubic-bezier(0.22, 1, 0.36, 1);
  --duration-fast: 150ms;
  --duration-base: 240ms;
  --duration-slow: 420ms;

  --popup-item-foreground: var(--foreground);
  --popup-item-icon-foreground: currentColor;
  --popup-item-highlight-background: oklch(from var(--foreground) l c h / 0.06);
  --badge-neutral: oklch(from var(--foreground) l c h / 0.08);
  --badge-neutral-foreground: var(--foreground);
  --badge-neutral-border: oklch(from var(--foreground) l c h / 0.1);
  --badge-neutral-hover: oklch(from var(--foreground) l c h / 0.12);
  --badge-slate: oklch(from var(--color-slate-500) l c h / 0.14);
  --badge-slate-foreground: var(--color-slate-800);
  --badge-slate-border: oklch(from var(--color-slate-500) l c h / 0.18);
  --badge-slate-hover: oklch(from var(--color-slate-500) l c h / 0.2);
  --badge-gray: oklch(from var(--color-gray-500) l c h / 0.14);
  --badge-gray-foreground: var(--color-gray-800);
  --badge-gray-border: oklch(from var(--color-gray-500) l c h / 0.18);
  --badge-gray-hover: oklch(from var(--color-gray-500) l c h / 0.2);
  --badge-zinc: oklch(from var(--color-zinc-500) l c h / 0.14);
  --badge-zinc-foreground: var(--color-zinc-800);
  --badge-zinc-border: oklch(from var(--color-zinc-500) l c h / 0.18);
  --badge-zinc-hover: oklch(from var(--color-zinc-500) l c h / 0.2);
  --badge-stone: oklch(from var(--color-stone-500) l c h / 0.14);
  --badge-stone-foreground: var(--color-stone-800);
  --badge-stone-border: oklch(from var(--color-stone-500) l c h / 0.18);
  --badge-stone-hover: oklch(from var(--color-stone-500) l c h / 0.2);
  --badge-red: oklch(from var(--color-red-500) l c h / 0.14);
  --badge-red-foreground: var(--color-red-800);
  --badge-red-border: oklch(from var(--color-red-500) l c h / 0.18);
  --badge-red-hover: oklch(from var(--color-red-500) l c h / 0.2);
  --badge-orange: oklch(from var(--color-orange-500) l c h / 0.16);
  --badge-orange-foreground: var(--color-orange-800);
  --badge-orange-border: oklch(from var(--color-orange-500) l c h / 0.2);
  --badge-orange-hover: oklch(from var(--color-orange-500) l c h / 0.24);
  --badge-amber: oklch(from var(--color-amber-400) l c h / 0.2);
  --badge-amber-foreground: var(--color-amber-800);
